import{_ as a,c as t,o as i,ag as o}from"./chunks/framework.DPDPlp3K.js";const n="/assets/collage.DKGrBvB9.webp",m=JSON.parse('{"title":"What is SQLRooms?","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/overview.html"}]]},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),r={name:"overview.md"};function s(l,e,c,d,h,p){return i(),t("div",null,e[0]||(e[0]=[o('<h1 id="what-is-sqlrooms" tabindex="-1">What is SQLRooms? <a class="header-anchor" href="#what-is-sqlrooms" aria-label="Permalink to &quot;What is SQLRooms?&quot;">​</a></h1><p>SQLRooms provides a foundation and set of building blocks for creating data analytics applications that run entirely in the browser. It combines essential components like a SQL query engine (DuckDB), data visualization tools, state management, and UI components into a cohesive toolkit, making it significantly easier to create powerful analytics tools without a backend.</p><a href="/examples"><img src="'+n+'" alt="SQLRooms example apps" width="600"></a><h2 id="who-is-it-for" tabindex="-1">Who is it for? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who is it for?&quot;">​</a></h2><p>SQLRooms is designed for developers building:</p><ul><li>Interactive data analysis tools</li><li>Custom BI solutions</li><li>Data visualization applications</li><li>Internal analytics dashboards</li></ul><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Modern data analytics applications face several challenges that SQLRooms addresses:</p><h3 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h3><p>Building analytics applications typically requires integrating multiple complex components. SQLRooms provides a complete foundation with state management, UI components, and <a href="/architecture.html">extensible architecture</a> out of the box.</p><h3 id="performance-and-scale" tabindex="-1">Performance and Scale <a class="header-anchor" href="#performance-and-scale" aria-label="Permalink to &quot;Performance and Scale&quot;">​</a></h3><p>DuckDB is purpose-built for analytics, providing fast query performance on large datasets through its columnar engine and optimized query processing. Running in the browser through WebAssembly, each user gets their own instance, enabling automatic scaling without infrastructure costs. Applications can even work offline, as there&#39;s no dependency on backend services.</p><h3 id="ai-powered-analytics" tabindex="-1">AI-Powered Analytics <a class="header-anchor" href="#ai-powered-analytics" aria-label="Permalink to &quot;AI-Powered Analytics&quot;">​</a></h3><p>The browser-based DuckDB engine enables powerful AI-driven analytics workflows:</p><ul><li>Interactive AI agents that can write and execute SQL queries</li><li>Automated data analysis and insights generation</li></ul><p>Check out our <a href="/examples.html#ai-powered-analytics">AI example</a> that demonstrates how to build an AI agent that can analyze your data using natural language, execute SQL queries, and provide insights – all running directly in the browser.</p><h3 id="privacy-and-security" tabindex="-1">Privacy and Security <a class="header-anchor" href="#privacy-and-security" aria-label="Permalink to &quot;Privacy and Security&quot;">​</a></h3><p>SQLRooms enables applications where sensitive data can remain completely client-side, as all data processing and analysis can be performed directly in the browser using DuckDB. This architecture allows for implementations where data never needs to leave the client, simplifying compliance and security requirements when needed.</p><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>SQLRooms provides a powerful foundation for building browser-based data analytics applications with no backend requirements. By combining DuckDB&#39;s SQL engine with modern web technologies, it enables developers to create performant, scalable, and privacy-focused data tools.</p><p>Ready to dive deeper? Check out our <a href="/architecture.html">Architecture Guide</a> to understand how SQLRooms components work together and how you can leverage them in your applications.</p>',21)]))}const f=a(r,[["render",s]]);export{m as __pageData,f as default};
